import { createBrowserClient } from "@supabase/ssr";

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

export const createClient = (): any => {
  if (!supabaseUrl || !supabaseKey) {
    // Provide a safe no-op mock client so the app doesn't crash at runtime.
    // This allows the app to render and present a helpful message to the developer.
    const msg =
      'Missing Supabase environment variables. Please create a .env.local file with:\n' +
      'NEXT_PUBLIC_SUPABASE_URL=your-project-url\n' +
      'NEXT_PUBLIC_SUPABASE_ANON_KEY=your-anon-key';

    // eslint-disable-next-line no-console
    console.warn(msg);

    const noop = {
      auth: {
        getSession: async () => ({ data: { session: null } }),
        onAuthStateChange: (_: any) => ({ data: { subscription: { unsubscribe: () => {} } } }),
        signUp: async () => ({ error: new Error(msg) }),
        signInWithPassword: async () => ({ error: new Error(msg) }),
        signOut: async () => ({}),
      },
    };

    return noop;
  }

  return createBrowserClient(supabaseUrl, supabaseKey);
};
